10: pub struct SessionManager {
11:     session: Arc<RwLock<Option<Arc<Session>>>>,
12:     config: ZenohConfig,
13: }
14: 
15: impl SessionManager {
16:     /// Convenience: create SessionManager with defaults and auto-connect
17:     pub async fn connected() -> Result<Arc<Self>, ZenohError> {
18:         let sm = Self::new(ZenohConfig::default());
19:         sm.connect().await?;
20:         Ok(Arc::new(sm))
21:     }
22: 
23:     /// Create a builder for SessionManager configuration
24:     pub fn builder() -> SessionManagerBuilder {
25:         SessionManagerBuilder::default()
26:     }
27: 
28:     /// Connect and wrap self in Arc
29:     pub async fn connect_and_wrap(self) -> Result<Arc<Self>, ZenohError> {
30:         self.connect().await?;
31:         Ok(Arc::new(self))
32:     }
33: 
34:     pub fn new(config: ZenohConfig) -> Self {
35:         Self {
36:             session: Arc::new(RwLock::new(None)),
37:             config,
38:         }
39:     }
40: 
41:     pub async fn connect(&self) -> Result<Arc<Session>, ZenohError> {
42:         let mut guard = self.session.write().await;
43:         if guard.is_some() {
44:             return Err(ZenohError::AlreadyConnected);
45:         }
46: 
47:         // Build bus config from ZenohConfig with fast accept timeout for quick operations
48:         let mut zenoh_config_json = serde_json::json!({
49:             "mode": self.config.mode,
50:             "scouting": {
51:                 "multicast": {
52:                     "enabled": true
53:                 }
54:             },
55:             "transport": {
56:                 "unicast": {
57:                     "accept_timeout": 100  // ms - Fast accept timeout
58:                 }
59:             }
60:         });
61: 
62:         if !self.config.connect.is_empty() {
63:             zenoh_config_json["connect"]["endpoints"] = serde_json::json!(self.config.connect);
64:         }
65: 
66:         if !self.config.listen.is_empty() {
67:             zenoh_config_json["listen"]["endpoints"] = serde_json::json!(self.config.listen);
68:         }
69: 
70:         let zenoh_config: zenoh::Config = serde_json::from_value(zenoh_config_json)
71:             .map_err(|e| ZenohError::Session(e.to_string()))?;
72: 
73:         let session = zenoh::open(zenoh_config).await?;
74:         let session = Arc::new(session);
75:         *guard = Some(session.clone());
76: 
77:         Ok(session)
78:     }
79: 
80:     pub async fn disconnect(&self) -> Result<(), ZenohError> {
81:         let mut guard = self.session.write().await;
82:         if let Some(session) = guard.take() {
83:             session.close().await?;
84:         }
85:         Ok(())
86:     }
87: 
88:     /// Disconnect with timeout - prevents blocking indefinitely on slow peer disconnection
89:     /// Returns Timeout error if session close doesn't complete within timeout
90:     pub async fn disconnect_with_timeout(
91:         &self,
92:         timeout: std::time::Duration,
93:     ) -> Result<(), ZenohError> {
94:         let mut guard = self.session.write().await;
95:         if let Some(session) = guard.take() {
96:             tokio::time::timeout(timeout, session.close())
97:                 .await
98:                 .map_err(|_| ZenohError::Timeout)?
99:                 .map_err(ZenohError::from)?;
100:         }
101:         Ok(())
102:     }
103: 
104:     /// Disconnect asynchronously without waiting for completion
105:     /// Returns a JoinHandle that can be awaited if needed, or ignored for fire-and-forget
106:     pub fn disconnect_async(self: Arc<Self>) -> tokio::task::JoinHandle<()> {
107:         tokio::spawn(async move {
108:             let mut guard = self.session.write().await;
109:             if let Some(session) = guard.take() {
110:                 let _ = session.close().await;
111:             }
112:         })
113:     }
