124: impl Agent {
125:     pub fn new(config: AgentConfig, llm: Arc<dyn LlmClient>) -> Self {
126:         Self {
127:             config,
128:             llm,
129:             message_log: MessageLog::new(),
130:             tool_registry: None,
131:         }
132:     }
