134:     pub fn new_with_registry(config: AgentConfig, llm: Arc<dyn LlmClient>, registry: Arc<ToolRegistry>) -> Self {
135:         Self {
136:             config,
137:             llm,
138:             message_log: MessageLog::new(),
139:             tool_registry: Some(registry),
140:         }
141:     }
