148:         &self.config
149:     }
150: 
151:     /// Get the tool registry if one is attached.
152:     pub fn get_tool_registry(&self) -> Option<&Arc<ToolRegistry>> {
153:         self.tool_registry.as_ref()
154:     }
155: 
156:     /// Register a tool with the internal registry.
157:     pub fn register_tool(&mut self, tool: Arc<dyn Tool>) -> Result<(), ToolError> {
158:         match self.tool_registry.take() {
159:             Some(registry) => {
160:                 let mut new_registry = ToolRegistry::new();
161:                 for name in registry.list() {
162:                     if let Some(t) = registry.get(&name) {
163:                         new_registry.register(t)?;
164:                     }
165:                 }
166:                 new_registry.register(tool)?;
167:                 self.tool_registry = Some(Arc::new(new_registry));
168:                 Ok(())
169:             }
170:             None => {
171:                 let mut registry = ToolRegistry::new();
172:                 registry.register(tool)?;
173:                 self.tool_registry = Some(Arc::new(registry));
174:                 Ok(())
175:             }
176:         }
177:     }
178: 
179:     /// Register a tool, panics on error (convenience method).
180:     pub fn add_tool(&mut self, tool: Arc<dyn Tool>) {
181:         self.register_tool(tool).expect("failed to add tool");
182:     }
183: 
184:     /// Builder-style method to add a tool and return self.
185:     pub fn with_tool(mut self, tool: Arc<dyn Tool>) -> Self {
186:         self.add_tool(tool);
187:         self
188:     }
