190:     /// Register a function as a tool using FunctionTool wrapper.
191:     pub fn register_function<F>(
192:         &mut self,
193:         name: &str,
194:         description: &str,
195:         schema: serde_json::Value,
196:         func: F,
197:     ) -> Result<(), ToolError>
198:     where
199:         F: Fn(&serde_json::Value) -> Result<serde_json::Value, ToolError> + Send + Sync + 'static,
200:     {
201:         let tool = Arc::new(FunctionTool::new(name, description, schema, func));
202:         self.register_tool(tool)
203:     }
204: 
205:     /// Register a numeric function as a tool with auto-generated schema.
206:     /// The function should accept `&serde_json::Value` and return `Result<serde_json::Value, ToolError>`.
207:     pub fn register_numeric_function<F>(
208:         &mut self,
209:         name: &str,
210:         description: &str,
211:         num_params: usize,
212:         func: F,
213:     ) -> Result<(), ToolError>
214:     where
215:         F: Fn(&serde_json::Value) -> Result<serde_json::Value, ToolError> + Send + Sync + 'static,
216:     {
217:         let tool = Arc::new(FunctionTool::numeric(name, description, num_params, func));
218:         self.register_tool(tool)
219:     }
