221:     /// Run agent on a task (no tools).
222:     pub async fn run(&mut self, task: &str) -> Result<String, AgentError> {
223:         self.message_log.add_user(task.to_string());
224:         let output = self.run_loop(None).await?;
225:         match output {
226:             AgentOutput::Text(text) => Ok(text),
227:             AgentOutput::Error(e) => Err(AgentError::Session(e)),
228:         }
229:     }
