231:     /// Run agent on a task with tools available.
232:     /// Uses internal registry if available, falls back to external parameter.
233:     pub async fn run_with_tools(
234:         &mut self,
235:         task: &str,
236:         tools: Option<&ToolRegistry>,
237:     ) -> Result<AgentOutput, AgentError> {
238:         self.message_log.add_user(task.to_string());
239:         if self.tool_registry.is_some() {
240:             let registry = self.tool_registry.take().unwrap();
241:             let result = self.run_loop(Some(&registry)).await;
242:             self.tool_registry = Some(registry);
243:             result
244:         } else {
245:             self.run_loop(tools).await
246:         }
247:     }
