249:     /// Stream agent execution on a task (no tools).
250:     /// Returns a stream of tokens as they arrive.
251:     pub fn stream_run(
252:         &mut self,
253:         task: &str,
254:     ) -> Pin<Box<dyn Stream<Item = Result<StreamToken, AgentError>> + Send>> {
255:         self.message_log.add_user(task.to_string());
256:         self.stream_loop(None)
257:     }
258: 
259:     /// Run agent on a task with tools available, streaming results.
260:     /// Uses internal registry if available, falls back to external parameter.
261:     pub fn run_streaming_with_tools(
262:         &mut self,
263:         task: &str,
264:         tools: Option<Arc<ToolRegistry>>,
265:     ) -> Pin<Box<dyn Stream<Item = Result<StreamToken, AgentError>> + Send>> {
266:         self.message_log.add_user(task.to_string());
267: 
268:         if self.tool_registry.is_some() {
269:             self.stream_loop(self.tool_registry.clone())
270:         } else {
271:             self.stream_loop(tools)
272:         }
273:     }
