37: impl ZenohRpcDiscovery {
38:     /// Create a new Zenoh RPC discovery with default config.
39:     pub fn new(session: Arc<Session>) -> Self {
40:         Self {
41:             session,
42:             config: ZenohRpcDiscoveryConfig::default(),
43:         }
44:     }
45: 
46:     /// Create with custom configuration.
47:     pub fn with_config(session: Arc<Session>, config: ZenohRpcDiscoveryConfig) -> Self {
48:         Self { session, config }
49:     }
50: 
51:     /// Set service prefix filter.
52:     pub fn service_prefix(mut self, prefix: impl Into<String>) -> Self {
53:         self.config.service_prefix = Some(prefix.into());
54:         self
55:     }
56: 
57:     /// Set discovery timeout.
58:     pub fn timeout(mut self, timeout: Duration) -> Self {
59:         self.config.timeout = timeout;
60:         self
61:     }
62: 
63:     fn parse_tool_name(topic_prefix: &str) -> Option<(String, String)> {
64:         // Expected format: "agent/{agent_id}/tools/{tool_name}" or "rpc/{service_name}/{tool_name}"
65:         let parts: Vec<&str> = topic_prefix.split('/').collect();
66:         
67:         // Format: agent/{agent_id}/tools/{tool_name}
68:         if parts.len() >= 4 && parts[0] == "agent" && parts[2] == "tools" {
69:             let agent_id = parts[1].to_string();
70:             let tool_name = parts[3].to_string();
71:             return Some((agent_id, tool_name));
72:         }
73:         
74:         // Format: rpc/{service_name}/{tool_name}
75:         if parts.len() >= 3 && parts[0] == "rpc" {
76:             let service_name = parts[1].to_string();
77:             let tool_name = parts[2..].join("/");
78:             return Some((service_name, tool_name));
79:         }
80:         
81:         None
82:     }
83: }
