85: #[async_trait]
86: impl ToolDiscovery for ZenohRpcDiscovery {
87:     async fn discover_all(&self) -> Result<Vec<DiscoveredTool>, crate::error::ToolError> {
88:         let registry = DiscoveryRegistry::new()
89:             .session(self.session.clone())
90:             .timeout(self.config.timeout);
91: 
92:         let services = registry.list_services().await
93:             .map_err(|e| crate::error::ToolError::ExecutionFailed(e.to_string()))?;
94: 
95:         let mut tools = Vec::new();
96:         
97:         for service in services {
98:             // Apply prefix filter if configured
99:             if let Some(ref prefix) = self.config.service_prefix {
100:                 if !service.topic_prefix.starts_with(prefix) {
101:                     continue;
102:                 }
103:             }
104: 
105:             // Parse tool name from topic prefix
106:             if let Some((agent_or_service, tool_name)) = Self::parse_tool_name(&service.topic_prefix) {
107:                 // Create a discovered tool with default schema
108:                 // Actual schema would need to be queried from the service
109:                 let tool = DiscoveredTool {
110:                     name: tool_name.clone(),
111:                     description: format!("Remote tool: {} (via {})", tool_name, service.service_name),
112:                     input_schema: serde_json::json!({
113:                         "type": "object",
114:                         "properties": {},
115:                         "description": "Remote tool - schema unknown, contact service for details"
116:                     }),
117:                     source: ToolSource::ZenohRpc {
118:                         service_name: service.service_name.clone(),
119:                         agent_id: if service.topic_prefix.starts_with("agent/") {
120:                             Some(agent_or_service.clone())
121:                         } else {
122:                             None
123:                         },
124:                     },
125:                 };
126:                 tools.push(tool);
127:             }
128:         }
129: 
130:         Ok(tools)
131:     }
