7: 
8: /// Tool implementation that calls remote agent tools via A2A protocol.
9: ///
10: /// This allows an agent to invoke tools on another agent through
11: /// the A2A task delegation mechanism.
12: pub struct A2AToolClient {
13:     session: Arc<Session>,
14:     target_agent: AgentIdentity,
15:     tool_name: String,
16:     description: String,
17:     schema: serde_json::Value,
18:     timeout: std::time::Duration,
19: }
20: 
21: impl A2AToolClient {
22:     /// Create a new A2A tool client.
23:     pub fn new(
24:         session: Arc<Session>,
25:         target_agent: AgentIdentity,
26:         tool_name: impl Into<String>,
27:         description: impl Into<String>,
28:         schema: serde_json::Value,
29:     ) -> Self {
30:         Self {
31:             session,
32:             target_agent,
33:             tool_name: tool_name.into(),
34:             description: description.into(),
35:             schema,
36:             timeout: std::time::Duration::from_secs(60),
37:         }
38:     }
39: 
40:     /// Set a custom timeout for tool calls.
41:     pub fn with_timeout(mut self, timeout: std::time::Duration) -> Self {
42:         self.timeout = timeout;
43:         self
44:     }
45: 
46:     /// Get the target agent identity.
47:     pub fn target_agent(&self) -> &AgentIdentity {
48:         &self.target_agent
49:     }
50: }
51: 
52: #[async_trait]
53: impl Tool for A2AToolClient {
54:     fn name(&self) -> &str {
55:         &self.tool_name
56:     }
57: 
58:     fn description(&self) -> ToolDescription {
59:         ToolDescription {
60:             short: format!("{} (via A2A from {})", self.description, self.target_agent.name),
61:             parameters: self.schema.to_string(),
62:         }
63:     }
64: 
65:     fn json_schema(&self) -> serde_json::Value {
66:         self.schema.clone()
67:     }
68: 
69:     async fn execute(&self, args: &serde_json::Value) -> Result<serde_json::Value, ToolError> {
70:         // Create A2A client with a sender identity
71:         // In real usage, the agent would pass its own identity
72:         let sender_identity = AgentIdentity::new(
73:             uuid::Uuid::new_v4().to_string(),
74:             "tool-caller".to_string(),
75:             "1.0.0".to_string(),
76:         );
77:         
78:         let client = A2AClient::new(self.session.clone(), sender_identity);
79: 
80:         // Create a task with the tool call
81:         let task_input = serde_json::json!({
82:             "tool": self.tool_name,
83:             "arguments": args,
84:         });
85: 
86:         let task = Task::new(
87:             uuid::Uuid::new_v4().to_string(),
88:             task_input,
89:         );
90: 
91:         // Delegate task to the target agent
92:         let result_task = client.delegate_task(&self.target_agent, task).await
93:             .map_err(|e| ToolError::ExecutionFailed(format!("A2A delegation failed: {}", e)))?;
94: 
95:         // Check task state
96:         match result_task.state {
97:             TaskState::Completed => {
98:                 result_task.output.ok_or_else(|| {
99:                     ToolError::ExecutionFailed("Task completed but no output".to_string())
100:                 })
101:             }
102:             TaskState::Failed => {
103:                 Err(ToolError::ExecutionFailed(
104:                     result_task.error.unwrap_or_else(|| "Unknown error".to_string())
105:                 ))
106:             }
107:             TaskState::Canceled => {
108:                 Err(ToolError::ExecutionFailed("Task was canceled".to_string()))
109:             }
110:             _ => {
111:                 Err(ToolError::ExecutionFailed(format!(
112:                     "Unexpected task state: {:?}",
113:                     result_task.state
114:                 )))
115:             }
116:         }
117:     }
118: }
