10: /// Configuration for Zenoh RPC discovery.
11: #[derive(Debug, Clone)]
12: pub struct ZenohRpcDiscoveryConfig {
13:     /// Prefix filter for service names (e.g., "agent/")
14:     pub service_prefix: Option<String>,
