32: impl RpcHandler for ToolHandler {
33:     async fn handle(&self, method: &str, payload: &[u8]) -> Result<Vec<u8>, RpcServiceError> {
34:         println!("[Provider] Received RPC call: {}", method);
35: 
36:         let args: Value = serde_json::from_slice(payload)
37:             .map_err(|e| RpcServiceError::Internal(e.to_string()))?;
38: 
