51:                     .ok_or_else(|| RpcServiceError::Internal("Missing 'b'".to_string()))?;
52:                 json!(a * b)
53:             }
54:             _ => {
55:                 return Err(RpcServiceError::NotFound(format!("Unknown method: {}", method)));
56:             }
57:         };
58: 
59:         println!("[Provider] Returning result: {}", result);
60: 
61:         serde_json::to_vec(&result)
62:             .map_err(|e| RpcServiceError::Internal(e.to_string()))
63:     }
64: }

